class Solution {
    public long[] unmarkedSumArray(int[] nums, int[][] queries) {
        int n = nums.length;
        boolean[] marked = new boolean[n];
        long[] res = new long[queries.length];
        long sum = 0;
        for (int num : nums) {
            sum += num;
        }
        for (int i = 0; i < queries.length; i++) {
            int idx = queries[i][0];
            int k = queries[i][1];
            if (!marked[idx]) {
                marked[idx] = true;
                sum -= nums[idx];
            }
            int cnt = 0;
            for (int j = 0; j < n; j++) {
                if (!marked[j]) {
                    marked[j] = true;
                    sum -= nums[j];
                    cnt++;
                    if (cnt == k) {
                        break;
                    }
                }
            }
            res[i] = sum;
        }
        return res;
    }
}
